-- Batches 3-6: Health, Education, Safety, Business Essentials (12 services)
-- Health Certificate, Prenatal Checkup, Vaccination Programs
-- Scholarship Programs, Student Assistance
-- Emergency Response, Disaster Preparedness
-- Business Permit Renewal, Sanitary Permit, Business Closure, Tricycle Franchising, Tax Clearance

-- ===== BATCH 3: HEALTH SERVICES (3) =====

UPDATE services SET description='Certificate of good health issued by City Health Office. Required for employment, school enrollment, food handling jobs, and other purposes.', fees='₱50-₱100', processing_time='Same day', office='City Health Office', steps='[{"title":"Go to City Health Office","description":"Visit City Health Office at City Hall. Bring valid ID and requirements.","order":1},{"title":"Fill Out Form","description":"Complete health certificate application form with personal information and purpose.","order":2},{"title":"Medical Examination","description":"Undergo basic medical examination: blood pressure, weight, height, visual inspection. May require chest x-ray for food handlers.","order":3},{"title":"Pay Fee","description":"Pay health certificate fee (₱50-₱100) at cashier.","order":4},{"title":"Claim Certificate","description":"Certificate is usually released same day after examination and payment.","order":5}]'::jsonb, faq='[{"question":"What is health certificate used for?","answer":"Employment (especially food handling), school enrollment, sports participation, travel requirements, and other purposes requiring proof of good health.","order":1},{"question":"How long is health certificate valid?","answer":"Typically valid for 6 months to 1 year. Check with the requiring party for their validity requirement.","order":2},{"question":"Do I need fasting for health certificate?","answer":"Not usually required for basic health certificate. However, if blood test is needed, fasting may be required. Ask when scheduling.","order":3},{"question":"Can I get health certificate if I have illness?","answer":"Depends on the illness and purpose. Minor illnesses may not disqualify. Consult with health officer about your specific condition.","order":4},{"question":"What if I need chest x-ray?","answer":"Food handlers and some employment types require chest x-ray. Get x-ray first at accredited facility, then bring result to City Health Office.","order":5}]'::jsonb, office_details='{"name":"City Health Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"general":["Valid government-issued ID","1x1 ID photo (1 copy)","Payment: ₱50-₱100"],"food_handler":["Valid government-issued ID","1x1 ID photo (1 copy)","Chest X-ray result (not older than 6 months)","Stool examination result","Payment: ₱50-₱100"]}'::jsonb, related_services=ARRAY['medical-assistance','vaccination-programs'] WHERE slug='health-certificate';

UPDATE services SET description='Free prenatal checkup and maternal care services for pregnant women. Includes regular checkups, vitamins, health education, and monitoring throughout pregnancy.', fees='Free', processing_time='Walk-in (regular schedule)', office='City Health Office or Rural Health Units', steps='[{"title":"Register for Prenatal Care","description":"Visit City Health Office or nearest Rural Health Unit. Bring valid ID and any previous medical records if available.","order":1},{"title":"Initial Assessment","description":"Undergo initial prenatal assessment: medical history, physical examination, weight, blood pressure, and estimated due date.","order":2},{"title":"Laboratory Tests","description":"Free laboratory tests: urinalysis, blood typing, CBC, hepatitis B screening, syphilis test, HIV test (with consent).","order":3},{"title":"Receive Prenatal Record","description":"Get prenatal record booklet to track your pregnancy progress. Bring this to all checkups.","order":4},{"title":"Schedule Regular Checkups","description":"Follow recommended prenatal visit schedule: monthly until 7 months, bi-weekly until 9 months, weekly until delivery.","order":5},{"title":"Attend Health Education","description":"Participate in health education sessions on nutrition, breastfeeding, newborn care, and family planning.","order":6},{"title":"Receive Vitamins and Supplements","description":"Get free prenatal vitamins (iron, folic acid, calcium) and tetanus toxoid vaccination.","order":7}]'::jsonb, faq='[{"question":"When should I start prenatal checkup?","answer":"As soon as you confirm pregnancy, ideally within first 3 months (first trimester). Early prenatal care is important for healthy pregnancy.","order":1},{"question":"How often should I have prenatal checkup?","answer":"Monthly checkups until 7 months pregnant, bi-weekly from 7-9 months, then weekly until delivery. More frequent if high-risk pregnancy.","order":2},{"question":"Is prenatal care really free?","answer":"Yes, prenatal checkups, laboratory tests, vitamins, and tetanus vaccination are free at government health facilities (City Health Office, Rural Health Units).","order":3},{"question":"What if I have complications?","answer":"If complications are detected, you will be referred to hospital for specialized care. Emergency cases should go directly to hospital.","order":4},{"question":"Can I choose where to give birth?","answer":"Yes, but prenatal checkup at health center helps ensure safe delivery. You can deliver at health center (normal delivery) or hospital (with referral if needed).","order":5}]'::jsonb, office_details='{"name":"City Health Office / Rural Health Units","location":"City Hall or Barangay Health Centers","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"pregnant_woman":["Valid government-issued ID or any ID","Previous medical records (if available)","Prenatal record from previous facility (if transferring)"]}'::jsonb, related_services=ARRAY['medical-assistance','health-certificate','vaccination-programs'] WHERE slug='prenatal-checkup';

UPDATE services SET description='Free immunization programs for infants, children, and adults. Protects against preventable diseases through vaccines administered according to national immunization schedule.', fees='Free', processing_time='Walk-in (scheduled immunization days)', office='City Health Office or Rural Health Units', steps='[{"title":"Check Immunization Schedule","description":"Visit health center on scheduled immunization days (usually specific days per week). Bring child early morning to avoid long queues.","order":1},{"title":"Bring Immunization Record","description":"Bring immunization record booklet. If first time, you will be given a new booklet to track all vaccinations.","order":2},{"title":"Registration","description":"Register at health center. Provide child information: name, birthdate, address, parent/guardian details.","order":3},{"title":"Health Assessment","description":"Health worker will check child weight, temperature, and general health condition to ensure fit for vaccination.","order":4},{"title":"Receive Vaccination","description":"Child will receive vaccine according to age and immunization schedule. Multiple vaccines may be given in one visit.","order":5},{"title":"Observation Period","description":"Wait 15-30 minutes after vaccination for observation. Report any immediate adverse reactions to health worker.","order":6},{"title":"Next Schedule","description":"Health worker will inform you of next vaccination schedule. Mark it in your calendar and bring immunization record next visit.","order":7}]'::jsonb, faq='[{"question":"What vaccines are free?","answer":"All vaccines in national immunization program: BCG, Hepatitis B, DPT, OPV/IPV, Hib, PCV, MMR, MR. For children 0-5 years old. Some vaccines also available for adults (Td, flu, pneumonia for seniors).","order":1},{"question":"When should my baby get first vaccine?","answer":"BCG and Hepatitis B are given at birth or within first month. Follow immunization schedule: vaccines at 1.5, 2.5, 3.5, 9, and 12 months, then boosters at older ages.","order":2},{"question":"What if I missed a vaccination schedule?","answer":"Go to health center as soon as possible. Health worker will assess and continue immunization from where you left off. Do not restart from beginning.","order":3},{"question":"Are vaccines safe?","answer":"Yes, vaccines are safe and effective. Minor side effects (mild fever, soreness) are normal and temporary. Serious reactions are very rare. Benefits far outweigh risks.","order":4},{"question":"Can adults get vaccinated?","answer":"Yes, adults can get Td (tetanus-diphtheria) booster, flu vaccine, pneumonia vaccine (for seniors and high-risk), and COVID-19 vaccines. Check with health center for availability.","order":5}]'::jsonb, office_details='{"name":"City Health Office / Rural Health Units / Barangay Health Centers","location":"Various locations citywide","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Immunization days: Check with your local health center for schedule"}'::jsonb, requirements_by_type='{"infant_child":["Immunization record booklet (if available)","Birth certificate or any proof of age","Parent/guardian valid ID"],"adult":["Valid government-issued ID","Previous vaccination record (if available)"]}'::jsonb, related_services=ARRAY['prenatal-checkup','health-certificate','medical-assistance'] WHERE slug='vaccination-programs';

-- ===== BATCH 4: EDUCATION (2) =====

UPDATE services SET description='Scholarship programs for qualified students from elementary to college level. Provides financial assistance for tuition, books, and other educational expenses.', fees='Free (scholarship program)', processing_time='Varies (usually processed before school year)', office='City Social Welfare and Development Office (CSWDO)', steps='[{"title":"Check Eligibility","description":"Scholarships available for: honor students, indigent but deserving students, children of solo parents/PWDs/senior citizens. Check specific scholarship program requirements.","order":1},{"title":"Prepare Requirements","description":"Gather: report card/grades, certificate of enrollment, barangay indigency certificate (if applicable), valid ID, birth certificate, and other program-specific requirements.","order":2},{"title":"Get Application Form","description":"Obtain scholarship application form from CSWDO or school. Some scholarships may have online application.","order":3},{"title":"Fill Out Application","description":"Complete application form accurately. Attach all required documents. Write essay or personal statement if required.","order":4},{"title":"Submit Application","description":"Submit to CSWDO or designated office before deadline. Keep copy of application and acknowledgment receipt.","order":5},{"title":"Wait for Evaluation","description":"Applications will be evaluated based on academic performance, financial need, and other criteria. May include interview.","order":6},{"title":"Receive Notification","description":"Approved scholars will be notified. Attend orientation on scholarship terms, obligations, and renewal requirements.","order":7},{"title":"Comply with Requirements","description":"Maintain required grades, submit reports, and comply with scholarship conditions to continue receiving benefits.","order":8}]'::jsonb, faq='[{"question":"What scholarship programs are available?","answer":"City government scholarships, congressional scholarships, CHED/TESDA scholarships, private foundation scholarships. Programs vary by level (elementary, high school, college, vocational).","order":1},{"question":"What are the requirements to qualify?","answer":"Varies by program. Common: good academic standing, financial need (indigent), residency in Ormoc City. Some require specific GPA or honor student status.","order":2},{"question":"How much is the scholarship?","answer":"Varies by program and level. May cover full tuition, partial tuition, or provide allowance. College scholarships typically ₱10,000-₱40,000 per semester.","order":3},{"question":"When is the application period?","answer":"Usually before start of school year (March-June for June opening, September-November for October opening). Check announcements from CSWDO or schools.","order":4},{"question":"Can I apply to multiple scholarships?","answer":"Yes, you can apply to multiple programs. However, if you receive multiple scholarships, you may need to choose one or declare all sources.","order":5}]'::jsonb, office_details='{"name":"City Social Welfare and Development Office (CSWDO)","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"elementary_highschool":["Report card (previous school year)","Certificate of enrollment (current year)","Barangay Indigency Certificate","Birth certificate","Valid ID of parent/guardian","1x1 ID photo (2 copies)"],"college_vocational":["Transcript of Records or Report Card","Certificate of enrollment","Barangay Indigency Certificate","Birth certificate","Valid government-issued ID","1x1 ID photo (2 copies)","Recommendation letter (some programs)"]}'::jsonb, related_services=ARRAY['student-assistance','solo-parent-id','financial-assistance'] WHERE slug='scholarship-programs';

UPDATE services SET description='Educational assistance for students in need of financial support for school supplies, uniforms, projects, and other educational expenses not covered by scholarships.', fees='Free (assistance program)', processing_time='3-7 business days', office='City Social Welfare and Development Office (CSWDO)', steps='[{"title":"Assess Your Need","description":"Student assistance is for: school supplies, uniforms, project materials, transportation, or other educational needs. Prepare documentation of need.","order":1},{"title":"Prepare Requirements","description":"Bring: valid ID, barangay indigency certificate, certificate of enrollment, list of needed items with estimated cost, and proof of residency.","order":2},{"title":"Go to CSWDO","description":"Visit City Social Welfare and Development Office at City Hall during office hours.","order":3},{"title":"Fill Out Application","description":"Complete student assistance application form. Specify items needed and estimated cost.","order":4},{"title":"Submit Requirements","description":"Submit all documents. Ensure completeness to avoid delays in processing.","order":5},{"title":"Assessment","description":"Social worker will assess your need and verify documents. May conduct home visit if needed.","order":6},{"title":"Wait for Approval","description":"Processing takes 3-7 business days. Approval depends on assessment and fund availability.","order":7},{"title":"Claim Assistance","description":"If approved, claim assistance with valid ID. May be cash, voucher, or direct provision of items. Sign acknowledgment receipt.","order":8}]'::jsonb, faq='[{"question":"What is covered by student assistance?","answer":"School supplies, uniforms, shoes, bags, project materials, transportation allowance, and other educational needs not covered by scholarships.","order":1},{"question":"How much assistance can I get?","answer":"Amount varies based on need and fund availability. Typically ₱500-₱3,000 per student. Higher amounts for special cases (e.g., graduation expenses).","order":2},{"question":"Can I apply if I have scholarship?","answer":"Yes, student assistance can supplement scholarship. However, you must declare your scholarship and assistance will be for items not covered by scholarship.","order":3},{"question":"How often can I apply?","answer":"Usually once per school year. However, special cases or urgent needs may be considered. Check with CSWDO for specific guidelines.","order":4},{"question":"Is this different from scholarship?","answer":"Yes. Scholarships are for tuition and are merit/need-based with renewal requirements. Student assistance is one-time aid for specific educational needs.","order":5}]'::jsonb, office_details='{"name":"City Social Welfare and Development Office (CSWDO)","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"student":["Valid government-issued ID or School ID","Barangay Indigency Certificate","Certificate of Enrollment","List of needed items with estimated cost","Proof of residency","Report card (if available)"]}'::jsonb, related_services=ARRAY['scholarship-programs','financial-assistance','solo-parent-id'] WHERE slug='student-assistance';

-- ===== BATCH 5: SAFETY (2) =====

UPDATE services SET description='24/7 emergency response services for medical emergencies, accidents, disasters, and other crisis situations. Provides immediate assistance and coordination with hospitals and emergency services.', fees='Free', processing_time='Immediate response', office='City Disaster Risk Reduction and Management Office (CDRRMO)', steps='[{"title":"Call Emergency Hotline","description":"Dial emergency hotline: 911 (national) or local emergency number. Stay calm and speak clearly.","order":1},{"title":"Provide Information","description":"Give: exact location, nature of emergency, number of people involved, your contact number. Follow dispatcher instructions.","order":2},{"title":"Wait for Response Team","description":"Emergency responders will be dispatched immediately. Stay on the line if instructed. Keep area safe and accessible.","order":3},{"title":"Assist Response Team","description":"When responders arrive, provide additional information. Follow their instructions. Clear the way for emergency vehicles.","order":4},{"title":"Receive Emergency Care","description":"Responders will provide first aid, stabilization, and transport to hospital if needed. Family may accompany if space permits.","order":5}]'::jsonb, faq='[{"question":"What is considered an emergency?","answer":"Life-threatening situations: severe injuries, heart attack, stroke, difficulty breathing, severe bleeding, unconsciousness, major accidents, disasters.","order":1},{"question":"Is emergency response really free?","answer":"Yes, emergency response and ambulance service are free. However, hospital treatment costs will apply once at the hospital.","order":2},{"question":"How fast is the response time?","answer":"Response time varies by location and traffic. Urban areas: 5-15 minutes. Rural areas: 15-30 minutes. Critical cases are prioritized.","order":3},{"question":"Can I request ambulance for non-emergency?","answer":"Ambulance is for emergencies. For non-emergency medical transport, contact hospital or private ambulance services. Emergency ambulance should not be used for routine transport.","order":4},{"question":"What if I am not sure if it is emergency?","answer":"When in doubt, call. Dispatcher will assess and advise. Better to call and be safe than delay in real emergency.","order":5}]'::jsonb, office_details='{"name":"City Disaster Risk Reduction and Management Office (CDRRMO)","location":"City Hall","address":"Ormoc City, Leyte","phone":"911 (National Emergency) / +63 53 561 6000 (City Hall)","hours":"24/7 Emergency Response"}'::jsonb, requirements_by_type='{"emergency_call":["Clear description of emergency","Exact location or nearest landmark","Contact number","Number of people involved"]}'::jsonb, related_services=ARRAY['disaster-preparedness','medical-assistance','health-certificate'] WHERE slug='emergency-response';

UPDATE services SET description='Disaster preparedness programs and training to help communities prepare for and respond to natural disasters (typhoons, floods, earthquakes). Includes evacuation planning, emergency kits, and community drills.', fees='Free', processing_time='Ongoing programs', office='City Disaster Risk Reduction and Management Office (CDRRMO)', steps='[{"title":"Attend Community Orientation","description":"Participate in disaster preparedness orientation in your barangay. Learn about local hazards and evacuation procedures.","order":1},{"title":"Prepare Emergency Kit","description":"Assemble family emergency kit: water, food, first aid, flashlight, radio, batteries, important documents, cash, medicines.","order":2},{"title":"Create Family Emergency Plan","description":"Develop family plan: evacuation routes, meeting points, emergency contacts, responsibilities. Practice with family.","order":3},{"title":"Know Evacuation Centers","description":"Identify designated evacuation centers in your area. Know the routes and what to bring during evacuation.","order":4},{"title":"Participate in Drills","description":"Join community disaster drills (earthquake, fire, flood drills). Practice evacuation and emergency procedures.","order":5},{"title":"Stay Informed","description":"Monitor weather updates, disaster warnings, and official announcements. Follow CDRRMO and local government social media.","order":6},{"title":"Volunteer for Training","description":"Consider joining Community Emergency Response Team (CERT) or barangay disaster response team for advanced training.","order":7}]'::jsonb, faq='[{"question":"What disasters should we prepare for in Ormoc?","answer":"Typhoons, floods, landslides, earthquakes. Ormoc is prone to typhoons and flooding. Preparation is essential for safety.","order":1},{"question":"What should be in emergency kit?","answer":"Water (3-day supply), non-perishable food, first aid kit, flashlight, battery radio, batteries, whistle, dust masks, plastic sheeting, duct tape, important documents (waterproof), cash, medicines, hygiene items.","order":2},{"question":"When should we evacuate?","answer":"Evacuate when: forced evacuation order issued, rising floodwater, landslide warning, severe typhoon signal, or when you feel unsafe. Do not wait until last minute.","order":3},{"question":"Can we bring pets to evacuation center?","answer":"Policies vary by evacuation center. Some allow pets in designated areas. Prepare pet carrier and supplies. Check with barangay for specific rules.","order":4},{"question":"How do we get disaster updates?","answer":"Monitor: TV/radio news, PAGASA weather updates, NDRRMC advisories, LGU Ormoc official Facebook page, barangay announcements, text alerts (if registered).","order":5}]'::jsonb, office_details='{"name":"City Disaster Risk Reduction and Management Office (CDRRMO)","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM (24/7 during disasters)"}'::jsonb, requirements_by_type='{"community_training":["Interest to participate","Barangay residency"],"cert_volunteer":["18 years old and above","Physically fit","Commitment to training and service","Barangay endorsement"]}'::jsonb, related_services=ARRAY['emergency-response','barangay-clearance'] WHERE slug='disaster-preparedness';

-- ===== BATCH 6: BUSINESS ESSENTIALS (5) =====

UPDATE services SET description='Annual renewal of business permit for existing businesses. Must be renewed before January 20 each year to avoid penalties and continue legal operations.', fees='Varies (based on business type and gross sales)', processing_time='1-3 business days', office='Business Permits and Licensing Office', steps='[{"title":"Prepare for Renewal","description":"Renew before January 20 to avoid penalties. Prepare previous year business permit and financial documents.","order":1},{"title":"Update Business Information","description":"If there are changes (address, business name, ownership), update first at appropriate office (DTI/SEC/CDA).","order":2},{"title":"Secure Barangay Clearance","description":"Get current year barangay business clearance from your barangay. Bring previous permit and valid ID.","order":3},{"title":"Submit Renewal Application","description":"Go to Business Permits Office. Submit renewal form, previous permit, barangay clearance, cedula, and financial documents.","order":4},{"title":"Pay Renewal Fees","description":"Pay business tax and permit fees at City Treasurer. Fees based on previous year gross sales. Early renewal (before Jan 20) gets discount.","order":5},{"title":"Claim Renewed Permit","description":"After payment and clearance from all offices, claim renewed business permit. Display at business location.","order":6}]'::jsonb, faq='[{"question":"When is the deadline for renewal?","answer":"January 20 of each year. Renewing after this date incurs penalties and surcharges. Renew early to avoid rush and get discount.","order":1},{"question":"How much is the renewal fee?","answer":"Varies based on business type and gross sales. Generally lower than new application. Early renewal (before Jan 20) gets 10-20% discount.","order":2},{"question":"What if I miss the deadline?","answer":"You can still renew but will pay penalties (2% per month) and surcharges. Renew as soon as possible to minimize additional charges.","order":3},{"question":"Do I need new inspections for renewal?","answer":"Usually not required if no changes in business. However, some businesses (food, health-related) may need annual sanitary inspection.","order":4},{"question":"Can I renew online?","answer":"Some cities offer online renewal. Check with Business Permits Office if Ormoc has online renewal system available.","order":5}]'::jsonb, office_details='{"name":"Business Permits and Licensing Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"renewal":["Previous year Business Permit","Barangay Business Clearance (current year)","Community Tax Certificate (Cedula)","Financial Statement or Income Tax Return","Valid government-issued ID","Payment for renewal fees"]}'::jsonb, related_services=ARRAY['business-permit','barangay-clearance','community-tax-certificate'] WHERE slug='business-permit-renewal';

UPDATE services SET description='Sanitary permit required for food-related businesses, beauty salons, health facilities, and other establishments requiring health and sanitation compliance.', fees='₱500-₱2,000 (varies by business type)', processing_time='3-5 business days', office='City Health Office', steps='[{"title":"Determine if Required","description":"Sanitary permit required for: restaurants, food stalls, bakeries, meat shops, beauty salons, spas, clinics, and similar establishments.","order":1},{"title":"Prepare Establishment","description":"Ensure compliance with sanitation standards: clean facilities, proper ventilation, waste disposal, water supply, pest control.","order":2},{"title":"Gather Requirements","description":"Bring: business permit application/renewal, health certificates of all food handlers/staff, valid ID, barangay clearance.","order":3},{"title":"Submit Application","description":"Go to City Health Office. Submit sanitary permit application and requirements.","order":4},{"title":"Schedule Inspection","description":"Health inspector will schedule inspection of your establishment. Ensure all areas are clean and compliant.","order":5},{"title":"Undergo Inspection","description":"Inspector will check: cleanliness, food storage, equipment, waste disposal, water supply, staff hygiene. Note any deficiencies.","order":6},{"title":"Address Deficiencies","description":"If issues found, correct them and request re-inspection. Must pass inspection to get permit.","order":7},{"title":"Pay Fee and Claim Permit","description":"After passing inspection, pay sanitary permit fee. Claim permit and display at establishment.","order":8}]'::jsonb, faq='[{"question":"Who needs sanitary permit?","answer":"Food establishments (restaurants, carinderias, bakeries, food carts), beauty salons, spas, massage parlors, clinics, hospitals, and other health-related businesses.","order":1},{"question":"How much is sanitary permit?","answer":"₱500-₱2,000 depending on business type and size. Food establishments typically ₱1,000-₱2,000. Beauty salons ₱500-₱1,000.","order":2},{"question":"Do all employees need health certificate?","answer":"Yes, all food handlers and staff in direct contact with customers (salon, spa) must have valid health certificate with chest x-ray and stool exam.","order":3},{"question":"How long is sanitary permit valid?","answer":"Typically 1 year. Must be renewed annually along with business permit renewal.","order":4},{"question":"What if we fail inspection?","answer":"Correct the deficiencies noted by inspector and request re-inspection. Serious violations may result in suspension or closure until corrected.","order":5}]'::jsonb, office_details='{"name":"City Health Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"food_establishment":["Business Permit application or current permit","Health Certificates of all food handlers (with chest x-ray and stool exam)","Valid ID of owner","Barangay Clearance","Payment for sanitary permit fee"],"salon_spa":["Business Permit application or current permit","Health Certificates of all staff","Valid ID of owner","Barangay Clearance","Payment for sanitary permit fee"]}'::jsonb, related_services=ARRAY['business-permit','health-certificate','business-permit-renewal'] WHERE slug='sanitary-permit';

UPDATE services SET description='Process for closing a business permanently. Requires settlement of all obligations, clearances, and proper documentation to legally cease operations.', fees='Varies (based on pending obligations)', processing_time='1-2 weeks', office='Business Permits and Licensing Office', steps='[{"title":"Decide to Close","description":"Ensure decision is final. Closing business requires settling all obligations and cannot be easily reversed.","order":1},{"title":"Settle All Obligations","description":"Pay all pending taxes, fees, employee benefits, supplier debts, and other financial obligations.","order":2},{"title":"Get Tax Clearance","description":"Secure tax clearance from BIR (national) and City Treasurer (local) certifying no pending tax obligations.","order":3},{"title":"Notify Employees","description":"If you have employees, provide proper notice and settle all benefits (last pay, separation pay, 13th month, leave credits).","order":4},{"title":"Submit Closure Application","description":"Go to Business Permits Office. Submit business closure application with supporting documents.","order":5},{"title":"Surrender Business Permit","description":"Surrender your business permit and other business-related permits (sanitary, fire, etc.).","order":6},{"title":"Get Clearances","description":"Obtain clearances from all concerned offices: City Treasurer, City Health, BFP, and others as applicable.","order":7},{"title":"Receive Closure Certificate","description":"After all clearances, receive Certificate of Business Closure. Keep for your records.","order":8}]'::jsonb, faq='[{"question":"Why do I need to formally close my business?","answer":"Formal closure prevents accumulation of penalties and taxes. It clears your record and allows you to start new business in the future without issues.","order":1},{"question":"What happens if I just stop operating without closing?","answer":"Penalties and taxes continue to accumulate. May affect future business applications. Proper closure is important for clean record.","order":2},{"question":"Can I reopen after closing?","answer":"Yes, but you need to apply as new business. Previous business is permanently closed. Cannot simply reactivate closed business.","order":3},{"question":"What if I have pending taxes?","answer":"You must settle all pending taxes before closure. Payment plan may be arranged with City Treasurer if cannot pay in full immediately.","order":4},{"question":"How long does closure process take?","answer":"1-2 weeks if all obligations are settled and documents are complete. May take longer if there are pending issues to resolve.","order":5}]'::jsonb, office_details='{"name":"Business Permits and Licensing Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"business_closure":["Business Permit (original)","Tax Clearance from BIR","Tax Clearance from City Treasurer","Clearance from City Health Office (if applicable)","Clearance from Bureau of Fire Protection (if applicable)","Valid government-issued ID","Proof of settlement of obligations"]}'::jsonb, related_services=ARRAY['business-permit','tax-clearance','business-tax-payment'] WHERE slug='business-closure';

UPDATE services SET description='Franchise and registration for tricycle operators and drivers. Required to legally operate tricycle for public transport within Ormoc City.', fees='₱500-₱2,000 (varies by type)', processing_time='1-2 weeks', office='City Transportation Office or Tricycle Operators and Drivers Association (TODA)', steps='[{"title":"Check Eligibility","description":"Must be: Filipino citizen, at least 18 years old, with valid driver license (restriction code 1 for tricycle), and resident of Ormoc City.","order":1},{"title":"Prepare Tricycle","description":"Tricycle must comply with standards: proper registration, roadworthy condition, safety features, and route assignment.","order":2},{"title":"Join TODA","description":"Join the Tricycle Operators and Drivers Association for your route. Membership may be required for franchise.","order":3},{"title":"Gather Requirements","description":"Bring: driver license, tricycle OR/CR, barangay clearance, police clearance, cedula, valid ID, and TODA membership.","order":4},{"title":"Submit Application","description":"Go to City Transportation Office. Submit franchise application with all requirements.","order":5},{"title":"Pay Franchise Fee","description":"Pay tricycle franchise fee and other applicable charges at City Treasurer.","order":6},{"title":"Undergo Inspection","description":"Tricycle will be inspected for roadworthiness and compliance with standards. Must pass to get franchise.","order":7},{"title":"Claim Franchise and Plate","description":"After approval, claim franchise certificate and tricycle plate number. Display plate on tricycle.","order":8}]'::jsonb, faq='[{"question":"How much is tricycle franchise?","answer":"Franchise fee varies: ₱500-₱2,000 depending on route and type (operator or driver only). Annual renewal fees also apply.","order":1},{"question":"What is the difference between operator and driver franchise?","answer":"Operator owns the tricycle and has franchise. Driver only drives for operator. Both need appropriate franchise/permit to operate legally.","order":2},{"question":"Do I need to renew franchise?","answer":"Yes, tricycle franchise must be renewed annually. Renewal includes payment of fees and inspection of tricycle.","order":3},{"question":"Can I operate on any route?","answer":"No, tricycle franchise is route-specific. You can only operate on your assigned route. Operating outside route may result in penalties.","order":4},{"question":"What if my tricycle is old?","answer":"Tricycle must be roadworthy and pass inspection. Very old tricycles may not pass. Check with Transportation Office for age limits and requirements.","order":5}]'::jsonb, office_details='{"name":"City Transportation Office","location":"City Hall","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"operator":["Valid driver license (restriction code 1)","Tricycle OR (Official Receipt)","Tricycle CR (Certificate of Registration)","Barangay Clearance","Police Clearance","Community Tax Certificate (Cedula)","Valid government-issued ID","TODA membership certificate","Payment for franchise fee"],"driver":["Valid driver license (restriction code 1)","Barangay Clearance","Police Clearance","Community Tax Certificate (Cedula)","Valid government-issued ID","TODA membership certificate","Authorization from tricycle owner","Payment for driver permit fee"]}'::jsonb, related_services=ARRAY['barangay-clearance','police-clearance','community-tax-certificate'] WHERE slug='tricycle-franchising-records';

UPDATE services SET description='Tax clearance certificate confirming no pending tax obligations. Required for business closure, contract bidding, loan applications, and other transactions.', fees='₱100-₱200', processing_time='1-3 business days', office='City Treasurer Office', steps='[{"title":"Settle All Tax Obligations","description":"Ensure all taxes are paid: business tax, real property tax, and other local taxes. No pending obligations.","order":1},{"title":"Prepare Requirements","description":"Bring: valid ID, latest tax payment receipts, business permit (if business), tax declaration (if property tax), and cedula.","order":2},{"title":"Go to City Treasurer","description":"Visit City Treasurer Office at City Hall. Proceed to tax clearance section.","order":3},{"title":"Fill Out Application","description":"Complete tax clearance application form. Specify purpose of clearance (business closure, bidding, loan, etc.).","order":4},{"title":"Submit Requirements","description":"Submit application and all supporting documents. Staff will verify your tax records and payments.","order":5},{"title":"Verification Process","description":"Treasurer office will check records for any pending taxes or obligations. This may take 1-3 days.","order":6},{"title":"Pay Clearance Fee","description":"If no pending obligations, pay tax clearance fee (₱100-₱200) at cashier.","order":7},{"title":"Claim Tax Clearance","description":"Claim tax clearance certificate. Keep original for submission and photocopy for your records.","order":8}]'::jsonb, faq='[{"question":"What is tax clearance used for?","answer":"Business closure, government contract bidding, loan applications, business transfer, and other transactions requiring proof of no tax delinquency.","order":1},{"question":"How long is tax clearance valid?","answer":"Typically valid for 6 months to 1 year from issue date. Check with requiring party for their validity requirement.","order":2},{"question":"What if I have pending taxes?","answer":"You must settle all pending taxes first before tax clearance can be issued. Payment plan may be arranged if cannot pay in full.","order":3},{"question":"Is tax clearance same as tax receipt?","answer":"No. Tax receipt proves you paid specific tax. Tax clearance certifies you have no pending tax obligations overall.","order":4},{"question":"Can I get tax clearance if I never had business?","answer":"Yes, you can get tax clearance for personal purposes (e.g., employment abroad, loan). It will certify no business or property tax obligations.","order":5}]'::jsonb, office_details='{"name":"City Treasurer Office","location":"City Hall, Ground Floor","address":"Ormoc City, Leyte","phone":"+63 53 561 6000","hours":"Monday to Friday: 8:00 AM - 5:00 PM"}'::jsonb, requirements_by_type='{"business":["Valid government-issued ID","Latest Business Tax Payment Receipt","Current Business Permit","Community Tax Certificate (Cedula)","Payment for clearance fee"],"property":["Valid government-issued ID","Latest Real Property Tax Receipt","Tax Declaration","Community Tax Certificate (Cedula)","Payment for clearance fee"],"personal":["Valid government-issued ID","Community Tax Certificate (Cedula)","Payment for clearance fee"]}'::jsonb, related_services=ARRAY['business-closure','real-property-tax','business-tax-payment'] WHERE slug='tax-clearance';
